        "testata": "Il Manifesto",
        "lingua_originale": "it",
        "titolo_orig": "Caro-carburanti: quando l’inazione è sovrana",
        "testo_it": "Il governo italiano non adotta misure contro il caro-carburanti, sperando in un calo dei prezzi a breve.",
        "priorita": "Bassa",
        "id_gruppo": 20,
        "link": "https://ilmanifesto.it/caro-carburanti-quando-linazione-e-sovrana",
        "orario": "00:05",
